INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0, 102301, "アヤネ", 401, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24001);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 2.21, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 0.0, 102301, "アヤネ", 402, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24002);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0, 102301, "アヤネ", 403, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24003);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 1.99, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 0.0, 192201, "アサヒ", 701, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24004);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 2.21, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 0.0, 192201, "アサヒ", 702, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24005);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 3.33, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 0.0, 192201, "アサヒ", 703, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24006);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0, 192301, "部員３", 801, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24007);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 2.68, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 0.0, 192301, "部員３", 802, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24008);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0, 192301, "部員３", 803, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24009);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "やった！", 0.0, 192501, "", 501, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 1, 24010);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "勝ったよ！", 0.0, 192501, "", 502, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 1, 24011);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "いい調子！", 0.0, 192501, "", 503, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 1, 24012);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 5.33, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 0.0, 113501, "ミサト", 111, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 6, 24013);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 6.85, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 0.0, 113501, "ミサト", 112, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24014);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 3.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 0.0, 113501, "ミサト", 113, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24015);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 6.11, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 0.0, 192401, "ダイチ", 611, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24016);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 6.75, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 0.0, 192401, "ダイチ", 612, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24017);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0, 192401, "ダイチ", 613, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24018);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 4.52, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 0.0, 113401, "ハツネ", 211, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24019);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 3.89, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 0.0, 113401, "ハツネ", 212, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24020);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 13.49, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 0.0, 113401, "ハツネ", 213, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24021);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 3.17, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 0.0, 106501, "カヤ", 311, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24022);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 4.42, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 0.0, 106501, "カヤ", 312, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24023);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 2.89, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 0.0, 106501, "カヤ", 313, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 6, 24024);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 3.71, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 0.0, 102301, "アヤネ", 421, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", 10046, 0.0, 4, 24025);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 5.1, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 0.0, 192201, "アサヒ", 721, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24026);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 4.34, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 0.0, 192301, "部員３", 821, "2030/12/17 14:59:59", 3, "2020/07/31 12:00:00", 10046, 0.0, 1, 24027);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "いい勝負だったよ\nまたやろうね", 0.0, 192501, "", 521, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 1, 24028);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 5.62, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", -360.0, 113501, "ミサト", 101, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24029);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 9.58, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", -360.0, 113501, "ミサト", 102, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24030);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", -360.0, 113501, "ミサト", 103, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 2, 24031);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 9.13, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", -360.0, 113501, "ミサト", 104, "2030/12/17 14:59:59", 1, "2020/07/31 12:00:00", 10046, 0.0, 2, 24032);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (24, 8.27, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", -360.0, 113501, "ミサト", 105, "2030/12/17 14:59:59", 2, "2020/07/31 12:00:00", 10046, 0.0, 1, 24033);
